
// ķó£Ķē▓ÕÅśķćÅ
$phone-bg: #1a1a1a;
$screen-bg: linear-gradient(180deg, #f8f9fa 0%, #e9ecef 100%);
$primary: #007aff;
$hp-color: #ff3b30;
$sp-color: #ffcc00;
$mood-color: #34c759;
$exp-color: #af52de;
$text-primary: #1c1c1e;
$text-secondary: #8e8e93;
$card-bg: #ffffff;

.phone-container {
  display: flex;
  justify-content: center;
  align-items: center;
  padding: 20px;
  min-height: 100%;
}

// µēŗµ£║Õż¢µĪå
.phone-frame {
  width: 100%;
  max-width: 375px;
  aspect-ratio: 9 / 19;
  background: $phone-bg;
  border-radius: 50px;
  padding: 12px;
  box-shadow:
    0 0 0 2px #2a2a2a,
    0 20px 60px rgba(0, 0, 0, 0.4),
    inset 0 0 20px rgba(255, 255, 255, 0.05);
  position: relative;
  display: flex;
  flex-direction: column;
}

// ÕłśµĄĘÕī║Õ¤¤
.notch-area {
  position: absolute;
  top: 0;
  left: 50%;
  transform: translateX(-50%);
  width: 160px;
  height: 35px;
  z-index: 100;

  .notch {
    position: absolute;
    bottom: 0;
    left: 50%;
    transform: translateX(-50%);
    width: 120px;
    height: 30px;
    background: #000;
    border-radius: 0 0 20px 20px;
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 8px;

    .camera {
      width: 10px;
      height: 10px;
      background: #1a1a1a;
      border-radius: 50%;
      box-shadow: inset 0 0 2px rgba(0, 0, 0, 0.5);
    }

    .speaker {
      width: 50px;
      height: 4px;
      background: #2a2a2a;
      border-radius: 2px;
    }
  }

  .status-icons {
    position: absolute;
    top: 12px;
    width: 100%;
    display: flex;
    justify-content: space-between;
    padding: 0 15px;
    color: #fff;
    font-size: 12px;
    font-weight: 600;

    .time {
      margin-left: 10px;
    }

    .icons {
      display: flex;
      gap: 5px;
      margin-right: 10px;

      i {
        font-size: 12px;
      }
    }
  }
}

// µēŗµ£║Õ▒ÅÕ╣Ģ
.phone-screen {
  flex: 1;
  background: $screen-bg;
  border-radius: 40px;
  overflow: hidden;
  display: flex;
  flex-direction: column;
  position: relative;
}

// ĶüŖÕż®Õż┤ķā©
.chat-header {
  background: $card-bg;
  padding: 50px 15px 12px;
  display: flex;
  align-items: center;
  gap: 10px;
  border-bottom: 1px solid #e5e5ea;

  .back-btn {
    color: $primary;
    font-size: 18px;
    cursor: pointer;
  }

  .contact-info {
    flex: 1;
    display: flex;
    align-items: center;
    gap: 10px;

    .avatar {
      width: 36px;
      height: 36px;
      background: linear-gradient(135deg, $primary, #5856d6);
      border-radius: 50%;
      display: flex;
      align-items: center;
      justify-content: center;
      color: #fff;
      font-size: 16px;
    }

    .contact-details {
      .contact-name {
        font-size: 16px;
        font-weight: 600;
        color: $text-primary;
      }

      .contact-status {
        font-size: 12px;
        color: $text-secondary;
        display: flex;
        align-items: center;
        gap: 4px;

        .online-dot {
          width: 8px;
          height: 8px;
          background: $mood-color;
          border-radius: 50%;
        }
      }
    }
  }

  .header-actions {
    display: flex;
    gap: 15px;
    color: $primary;
    font-size: 18px;

    i {
      cursor: pointer;
    }
  }
}

// ńŖČµĆüÕŹĪńēćÕī║Õ¤¤
.status-cards {
  padding: 15px;
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 12px;
  overflow-y: auto;
}

.status-card {
  background: $card-bg;
  border-radius: 16px;
  padding: 12px;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.04);

  &.hp-card {
    grid-column: 1 / -1;
    display: flex;
    align-items: center;
    gap: 15px;

    .card-content {
      flex: 1;
      display: flex;
      justify-content: center;
    }
  }

  .card-header {
    display: flex;
    align-items: center;
    gap: 6px;
    font-size: 13px;
    color: $text-secondary;
    margin-bottom: 8px;

    i {
      font-size: 14px;
    }
  }

  .card-content {
    .progress-ring {
      width: 80px;
      height: 80px;
      position: relative;

      svg {
        transform: rotate(-90deg);
        width: 100%;
        height: 100%;

        circle {
          fill: none;
          stroke-width: 8;

          &.progress-ring-bg {
            stroke: #f0f0f0;
          }

          &.progress-ring-fill {
            stroke-linecap: round;
            transition: stroke-dashoffset 0.3s ease;
          }

          &.hp-fill {
            stroke: $hp-color;
          }
        }
      }

      .progress-text {
        position: absolute;
        top: 50%;
        left: 50%;
        transform: translate(-50%, -50%);
        text-align: center;

        .value {
          font-size: 24px;
          font-weight: 700;
          color: $text-primary;
        }

        .max {
          font-size: 12px;
          color: $text-secondary;
        }
      }
    }

    .progress-bar {
      height: 8px;
      background: #f0f0f0;
      border-radius: 4px;
      overflow: hidden;
      margin-top: 8px;

      .progress-fill {
        height: 100%;
        border-radius: 4px;
        transition: width 0.3s ease;

        &.sp-fill {
          background: linear-gradient(90deg, $sp-color, #ff9500);
        }

        &.mood-fill {
          background: linear-gradient(90deg, $mood-color, #30d158);
        }

        &.exp-fill {
          background: linear-gradient(90deg, $exp-color, #bf5af2);
        }
      }
    }

    .progress-info {
      display: flex;
      justify-content: space-between;
      margin-top: 6px;
      font-size: 12px;
      color: $text-secondary;
    }

    .mood-display {
      display: flex;
      align-items: center;
      gap: 8px;
      margin-bottom: 8px;

      .mood-emoji {
        font-size: 24px;
      }

      .mood-text {
        font-size: 14px;
        color: $text-primary;
        font-weight: 500;
      }
    }

    .exp-info {
      display: flex;
      justify-content: space-between;
      font-size: 12px;
      color: $text-secondary;
      margin-bottom: 4px;
    }
  }
}

// Õ▒×µĆ¦Õī║Õ¤¤
.attributes-section {
  background: $card-bg;
  margin: 0 15px 15px;
  border-radius: 16px;
  padding: 15px;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.04);

  .section-title {
    font-size: 14px;
    font-weight: 600;
    color: $text-primary;
    margin-bottom: 12px;
    display: flex;
    align-items: center;
    gap: 6px;

    i {
      color: $primary;
    }
  }

  .attributes-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 12px;

    .attr-item {
      display: flex;
      flex-direction: column;
      align-items: center;
      gap: 6px;
      padding: 10px;
      background: #f8f9fa;
      border-radius: 12px;

      .attr-icon {
        width: 32px;
        height: 32px;
        background: linear-gradient(135deg, $primary, #5856d6);
        border-radius: 10px;
        display: flex;
        align-items: center;
        justify-content: center;
        color: #fff;
        font-size: 14px;
      }

      .attr-info {
        text-align: center;

        .attr-name {
          font-size: 11px;
          color: $text-secondary;
        }

        .attr-value {
          font-size: 16px;
          font-weight: 700;
          color: $text-primary;
        }
      }
    }
  }
}

// ĶüŖÕż®ĶŠōÕģźÕī║Õ¤¤
.chat-input-area {
  background: $card-bg;
  padding: 10px 15px 30px;
  border-top: 1px solid #e5e5ea;

  .input-container {
    display: flex;
    align-items: center;
    gap: 10px;

    i {
      font-size: 24px;
      color: $text-secondary;

      &.fa-plus-circle {
        color: $text-secondary;
      }
    }

    .input-box {
      flex: 1;
      background: #f2f2f7;
      border-radius: 20px;
      padding: 10px 15px;
      font-size: 14px;
      color: $text-secondary;
    }
  }
}

// Õ║Ģķā©µīćńż║µØĪ
.home-indicator {
  position: absolute;
  bottom: 8px;
  left: 50%;
  transform: translateX(-50%);
  width: 120px;
  height: 4px;
  background: #fff;
  border-radius: 2px;
  opacity: 0.5;
}
